('spanish:x-3-speaking-read-aloud-and-photo-card:fib:7581fb01', 'spanish', 'spanish:x-3-speaking-read-aloud-and-photo-card', 'X.3 Speaking: Read-Aloud and Photo Card', 'fib', 'fib', 1, '{"question": "El chico está _____ un libro en la foto. <span data-say=\"El chico está leyendo un libro en la foto.\" data-listen>El chico está leyendo un libro en la foto.</span>", "blankOptions": {"B1": ["leyendo", "veo", "alta", "comiendo"]}}'::jsonb, '{"blanks": {"B1": "leyendo"}}'::jsonb),
